post_crear_tipo.codigo:
fetch('http://localhost:4000/api/tipo', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    nombre: 'Documental',
    descripcion: 'Contenido de formato documental'
  })
})
  .then(response => response.json())
  .then(data => console.log(data))
  .catch(error => console.error('Error:', error));

